import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { getAllVariants } from "../services/ApiService";

import cretaImage from "../assets/creta.jpg";
import venueImage from "../assets/venue.jpg";
import i20Image from "../assets/i20.jpg";

function Home() {

    const [variants, setVariants] =
        useState([]);

    useEffect(() => {

        loadVariants();

    }, []);

    const loadVariants = async () => {

        try {

            const response =
                await getAllVariants();

            setVariants(
                response.data
            );

        } catch (error) {

            console.log(error);
        }
    };

    const getCarImage =
        (variantName) => {

            if (
                variantName === "Creta"
            ) {

                return cretaImage;
            }

            if (
                variantName === "Venue"
            ) {

                return venueImage;
            }

            if (
                variantName === "i20"
            ) {

                return i20Image;
            }

            return cretaImage;
        };

    return (

        <div>

            {/* HERO SECTION */}

            <div
                style={{
                    background:
                        "linear-gradient(135deg,#000,#444)",

                    color:
                        "white",

                    padding:
                        "30px 20px",

                    textAlign:
                        "center"
                }}
            >

                <h1
                    style={{
                        fontSize:
                            "42px"
                    }}
                >

                    Car Rental System

                </h1>

                <p
                    style={{
                        marginTop:
                            "5px",

                        fontSize:
                            "18px"
                    }}
                >

                    Book Your Dream Car
                    At Affordable Prices

                </p>

            </div>

            {/* VARIANTS */}

            <div
                style={{
                    padding:
                        "30px"
                }}
            >

                <h1
                    style={{
                        textAlign:
                            "center"
                    }}
                >

                    Available Cars

                </h1>

                <div
                    style={{

                        display:
                            "flex",

                        flexWrap:
                            "wrap",

                        justifyContent:
                            "center",

                        gap:
                            "25px",

                        marginTop:
                            "30px"
                    }}
                >

                    {
                        variants.map(
                            (variant) => (

                                <div

                                    key={
                                        variant.id
                                    }

                                    style={{

                                        width:
                                            "320px",

                                        backgroundColor:
                                            "white",

                                        borderRadius:
                                            "15px",

                                        overflow:
                                            "hidden",

                                        boxShadow:
                                            "0px 0px 15px rgba(0,0,0,0.15)"
                                    }}
                                >

                                    <img

                                        src={
                                            getCarImage(
                                                variant.variantName
                                            )
                                        }

                                        alt="car"

                                        style={{

                                            width:
                                                "100%",

                                            height:
                                                "220px",

                                            objectFit:
                                                "cover"
                                        }}
                                    />

                                    <div
                                        style={{
                                            padding:
                                                "20px"
                                        }}
                                    >

                                        <h2>

                                            {
                                                variant.variantName
                                            }

                                        </h2>

                                        <p>

                                            <b>
                                                Company:
                                            </b>

                                            {" "}

                                            {
                                                variant
                                                .carCompany
                                                ?.companyName
                                            }

                                        </p>

                                        <p>

                                            <b>
                                                Fuel:
                                            </b>

                                            {" "}

                                            {
                                                variant.fuelType
                                            }

                                        </p>

                                        <p>

                                            <b>
                                                Price:
                                            </b>

                                            {" "}

                                            ₹ {
                                                variant.pricePerDay
                                            }

                                            / Day

                                        </p>

                                        <p>

                                            <b>
                                                Available:
                                            </b>

                                            {" "}

                                            {
                                                variant.availableCars
                                            }

                                        </p>

                                        {
                                            Number(
                                                variant.availableCars
                                            ) > 0 ? (

                                                <div>

                                                    <span
                                                        style={{
                                                            backgroundColor:
                                                                "green",

                                                            color:
                                                                "white",

                                                            padding:
                                                                "5px 10px",

                                                            borderRadius:
                                                                "5px",

                                                            fontSize:
                                                                "12px"
                                                        }}
                                                    >

                                                        Available

                                                    </span>

                                                    <br />
                                                    <br />

                                                    <Link
                                                        to={
                                                            `/booking/${variant.id}`
                                                        }
                                                    >

                                                        <button
                                                            style={{

                                                                width:
                                                                    "100%",

                                                                padding:
                                                                    "12px",

                                                                backgroundColor:
                                                                    "#000",

                                                                color:
                                                                    "white",

                                                                border:
                                                                    "none",

                                                                borderRadius:
                                                                    "8px",

                                                                cursor:
                                                                    "pointer"
                                                            }}
                                                        >

                                                            Book Now

                                                        </button>

                                                    </Link>

                                                </div>

                                            ) : (

                                                <div>

                                                    <span
                                                        style={{
                                                            backgroundColor:
                                                                "red",

                                                            color:
                                                                "white",

                                                            padding:
                                                                "5px 10px",

                                                            borderRadius:
                                                                "5px",

                                                            fontSize:
                                                                "12px"
                                                        }}
                                                    >

                                                        Not Available

                                                    </span>

                                                    <br />
                                                    <br />

                                                    <button
                                                        disabled

                                                        style={{

                                                            width:
                                                                "100%",

                                                            padding:
                                                                "12px",

                                                            backgroundColor:
                                                                "gray",

                                                            color:
                                                                "white",

                                                            border:
                                                                "none",

                                                            borderRadius:
                                                                "8px",

                                                            cursor:
                                                                "not-allowed"
                                                        }}
                                                    >

                                                        Already Booked

                                                    </button>

                                                </div>

                                            )
                                        }

                                    </div>

                                </div>
                            )
                        )
                    }

                </div>

            </div>

        </div>
    );
}

export default Home;
